sql:
SELECT ROUND(100.0 * SUM(CASE WHEN s.code = 'SUCCESS' THEN 1 ELSE 0 END) / COUNT(*), 2) AS pct_success
FROM documents d
JOIN states s ON s.state_id = d.state_id;

SELECT d.mask, AVG(d.nb_pages) AS avg_pages
FROM documents d
GROUP BY d.mask;

SELECT AVG(d.nb_pages) AS moyenne_pages
FROM documents d
WHERE d.budget_type = 'BP';
